import { type Dispatch } from 'react';
import type { PinnedState, FilterBarReducerAction } from './filter-state.types.js';
/**
 * An object containing all currently set filter values mapped to their corresponding filter names.
 * @public
 */
export type FilterItemValues = Record<string, {
    value?: unknown;
}>;
/**
 * The state of the filter containing the currently set filter, and its pinned state.
 * @internal
 */
export type FilterState = {
    filters?: FilterItemValues;
    itemsPinnedState?: PinnedState;
};
/**
 * @internal
 */
export interface FilterBarContextProps {
    state: FilterState;
    showLabels: boolean;
    lastAddedItem: string | null;
    setLastAddedItem: (item: string | null) => void;
    dispatch: Dispatch<FilterBarReducerAction>;
    hasControlledPinnedState: boolean;
}
